import { useCallback } from 'react';
import { useAppDispatch, useAppSelector } from '@/store';
import {
  setSearch,
  toggleFilterType,
  toggleFilterExperience,
  toggleFilterWorkMode,
  toggleFilterCategory,
  setSalaryRange,
  setLocation,
  clearFilters,
  toggleSaveJob,
  applyToJob,
  setActiveSection,
  selectFilters,
  selectSavedJobs,
  selectAppliedJobs,
  selectFilteredJobs,
  selectFeaturedJobs,
  selectRecentJobs,
  selectSavedJobObjects,
  selectAppliedJobObjects,
  selectActiveSection,
} from '@/store/slices/jobsSlice';
import { JobType, ExperienceLevel, WorkMode } from '@/types/jobs';

export function useJobs() {
  const dispatch = useAppDispatch();

  const filteredJobs = useAppSelector(selectFilteredJobs);
  const featuredJobs = useAppSelector(selectFeaturedJobs);
  const recentJobs = useAppSelector(selectRecentJobs);
  const filters = useAppSelector(selectFilters);
  const savedJobIds = useAppSelector(selectSavedJobs);
  const appliedJobIds = useAppSelector(selectAppliedJobs);
  const savedJobObjects = useAppSelector(selectSavedJobObjects);
  const appliedJobObjects = useAppSelector(selectAppliedJobObjects);
  const activeSection = useAppSelector(selectActiveSection);

  const handleSearch = useCallback((q: string) => dispatch(setSearch(q)), [dispatch]);
  const handleToggleType = useCallback((t: JobType) => dispatch(toggleFilterType(t)), [dispatch]);
  const handleToggleExperience = useCallback((e: ExperienceLevel) => dispatch(toggleFilterExperience(e)), [dispatch]);
  const handleToggleWorkMode = useCallback((m: WorkMode) => dispatch(toggleFilterWorkMode(m)), [dispatch]);
  const handleToggleCategory = useCallback((c: string) => dispatch(toggleFilterCategory(c)), [dispatch]);
  const handleSalaryRange = useCallback((min: number, max: number) => dispatch(setSalaryRange({ min, max })), [dispatch]);
  const handleLocation = useCallback((loc: string) => dispatch(setLocation(loc)), [dispatch]);
  const handleClearFilters = useCallback(() => dispatch(clearFilters()), [dispatch]);
  const handleToggleSave = useCallback((id: string) => dispatch(toggleSaveJob(id)), [dispatch]);
  const handleApply = useCallback((id: string) => dispatch(applyToJob(id)), [dispatch]);
  const handleSetSection = useCallback((s: 'recommended' | 'recent' | 'saved' | 'applied') => dispatch(setActiveSection(s)), [dispatch]);

  const isJobSaved = useCallback((id: string) => savedJobIds.includes(id), [savedJobIds]);
  const isJobApplied = useCallback((id: string) => appliedJobIds.includes(id), [appliedJobIds]);

  const activeFilterCount =
    filters.types.length +
    filters.experience.length +
    filters.workMode.length +
    filters.categories.length +
    (filters.location ? 1 : 0);

  return {
    filteredJobs,
    featuredJobs,
    recentJobs,
    filters,
    savedJobObjects,
    appliedJobObjects,
    activeSection,
    activeFilterCount,
    isJobSaved,
    isJobApplied,
    savedCount: savedJobIds.length,
    appliedCount: appliedJobIds.length,
    handleSearch,
    handleToggleType,
    handleToggleExperience,
    handleToggleWorkMode,
    handleToggleCategory,
    handleSalaryRange,
    handleLocation,
    handleClearFilters,
    handleToggleSave,
    handleApply,
    handleSetSection,
  };
}
